mapper.select:
SELECT * FROM (
SELECT C.CON_ID, C.PRS_ID, (CASE WHEN (SELECT MEM_NAME FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) != '' THEN (SELECT MEM_NAME FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) ELSE (SELECT PRS_NAME FROM WH_PRESS WHERE PRS_ID = C.PRS_ID) END ) MEM_NAME, (CASE WHEN (SELECT MEM_PICTURE FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) != '' THEN (SELECT MEM_PICTURE FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) ELSE '' END) MEM_PICTURE, C.CON_TITLE, C.CON_SUBTITLE, C.CON_THUMNAIL, C.CON_VIDEO, C.CON_VIDEO_THUMNAIL, C.CON_YOUTUBE_URL, C.CON_BODY, C.CON_PREFIX, C.CON_IMPORTANCE, C.CON_PRICE, C.CON_META_YN, C.CON_USE_YN, C.CON_WRITE_YN, P.PRI_ID, IF(P.PRI_EXPD IS NULL, 0, IF((DATEDIFF(P.PRI_EXPD, DATE_FORMAT(NOW(), '%Y-%m-%d'))) < 0, 0, DATEDIFF(P.PRI_EXPD, DATE_FORMAT(NOW(), '%Y-%m-%d')) + 1)) AS CON_EXPD, (SELECT COUNT(*) FROM WH_CONT_CNT WCC WHERE WCC.CON_ID = C.CON_ID) AS CON_CNT, (SELECT COUNT(*) FROM WH_COMMENT WC WHERE WC.CON_ID = C.CON_ID AND WC.COM_USE_YN = 1) AS CON_COMMENT_CNT, date_format(C.CON_CREATE_DATE,'%Y-%m-%d %T') CON_CREATE_DATE, date_format(C.CON_UPDATE_DATE,'%Y-%m-%d %T') CON_UPDATE_DATE, CON_PRIOT, CON_TOP_YN, CON_TOP_DATE FROM WH_CONTENT C LEFT JOIN WH_PRICE P ON C.CON_ID = P.CON_ID AND P.MEM_ID = #{MEM_ID} AND DATE_FORMAT(NOW(), '%Y-%m-%d') <= P.PRI_EXPD WHERE C.CON_USE_YN = 1 AND CON_TYPE = #{CON_TYPE}
AND CON_CATEGORY = #{CON_CATEGORY}
AND APP_ID = #{APP_ID}
AND C.PRS_ID NOT IN( SELECT BLOCK_MEM_ID FROM WH_BLOCK WHERE MEM_ID= #{MEM_ID} )
UNION ALL SELECT C.CON_ID, C.PRS_ID, (CASE WHEN (SELECT MEM_NAME FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) != '' THEN (SELECT MEM_NAME FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) ELSE (SELECT PRS_NAME FROM WH_PRESS WHERE PRS_ID = C.PRS_ID) END ) MEM_NAME, (CASE WHEN (SELECT MEM_PICTURE FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) != '' THEN (SELECT MEM_PICTURE FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) ELSE '' END) MEM_PICTURE, C.CON_TITLE, C.CON_SUBTITLE, C.CON_THUMNAIL, C.CON_VIDEO, C.CON_VIDEO_THUMNAIL, C.CON_YOUTUBE_URL, C.CON_BODY, C.CON_PREFIX, C.CON_IMPORTANCE, C.CON_PRICE, C.CON_META_YN, C.CON_USE_YN, C.CON_WRITE_YN, P.PRI_ID, IF(P.PRI_EXPD IS NULL, 0, IF((DATEDIFF(P.PRI_EXPD, DATE_FORMAT(NOW(), '%Y-%m-%d'))) < 0, 0, DATEDIFF(P.PRI_EXPD, DATE_FORMAT(NOW(), '%Y-%m-%d')) + 1)) AS CON_EXPD, (SELECT COUNT(*) FROM WH_CONT_CNT WCC WHERE WCC.CON_ID = C.CON_ID) AS CON_CNT, (SELECT COUNT(*) FROM WH_COMMENT WC WHERE WC.CON_ID = C.CON_ID AND WC.COM_USE_YN = 1) AS CON_COMMENT_CNT, date_format(C.CON_CREATE_DATE,'%Y-%m-%d %T') CON_CREATE_DATE, date_format(C.CON_UPDATE_DATE,'%Y-%m-%d %T') CON_UPDATE_DATE, CON_PRIOT, CON_TOP_YN, CON_TOP_DATE FROM WH_CONTENT C LEFT JOIN WH_PRICE P ON C.CON_ID = P.CON_ID AND P.MEM_ID = #{MEM_ID} AND DATE_FORMAT(NOW(), '%Y-%m-%d') <= P.PRI_EXPD WHERE 1=1 AND C.CON_USE_YN = 1
AND CON_CATEGORY = #{CON_CATEGORY}
AND C.APP_ID IN ( SELECT APP_ID FROM WH_PRESS WHERE 1=1
AND PRS_TYPE= #{PRS_TYPE}
AND APP_ID != '1' )
AND CON_TYPE IN ('0','1','8')
AND CON_TYPE ='9'
) M ORDER BY CON_TOP_DATE DESC, ${SORT_ITEM} ${SORT_ORDER} LIMIT ${offset}, ${limit}

SELECT PRS_ID, MAX(CON_CREATE_DATE) as LATEST_DATE FROM WH_CONTENT WHERE CON_TYPE = #{CON_TYPE} AND CON_USE_YN = 1
AND PRS_ID NOT IN (SELECT BLOCK_MEM_ID FROM WH_BLOCK WHERE MEM_ID = #{MEM_ID})
GROUP BY PRS_ID ORDER BY LATEST_DATE DESC LIMIT ${offset}, ${limit}

SELECT * FROM (
SELECT C.CON_ID, C.PRS_ID, (CASE WHEN (SELECT MEM_NAME FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) != '' THEN (SELECT MEM_NAME FROM WH_MEMBER WHERE MEM_ID = C.PRS_ID) ELSE (SELECT PRS_NAME FROM WH_PRESS WHERE PRS_ID = C.PRS_ID) END ) MEM_NAME, C.CON_TITLE, C.CON_SUBTITLE, C.CON_THUMNAIL, C.CON_YOUTUBE_URL, C.CON_BODY, C.CON_PREFIX, C.CON_IMPORTANCE, C.CON_PRICE, C.CON_META_YN, C.CON_USE_YN, C.CON_WRITE_YN, P.PRI_ID, (SELECT COUNT(*) FROM WH_WATCH ww WHERE ww.CON_ID = C.CON_ID) CON_WATCH_COUNT, IF(P.PRI_EXPD IS NULL, 0, IF((DATEDIFF(P.PRI_EXPD, DATE_FORMAT(NOW(), '%Y-%m-%d'))) < 0, 0, DATEDIFF(P.PRI_EXPD, DATE_FORMAT(NOW(), '%Y-%m-%d')) + 1)) AS CON_EXPD, (SELECT COUNT(*) FROM WH_CONT_CNT WCC WHERE WCC.CON_ID = C.CON_ID) AS CON_CNT, date_format(C.CON_CREATE_DATE,'%Y-%m-%d %T') CON_CREATE_DATE, date_format(C.CON_UPDATE_DATE,'%Y-%m-%d %T') CON_UPDATE_DATE, CON_PRIOT, CON_TOP_YN, CON_TOP_DATE FROM WH_CONTENT C LEFT JOIN WH_PRICE P ON C.CON_ID = P.CON_ID AND P.MEM_ID = #{MEM_ID} AND DATE_FORMAT(NOW(), '%Y-%m-%d') <= P.PRI_EXPD WHERE C.CON_USE_YN = 1 AND CON_TYPE = #{CON_TYPE}
AND CON_CATEGORY = #{CON_CATEGORY}
AND APP_ID = #{APP_ID} ) M
WHERE PRS_ID = #{MEM_ID}
ORDER BY CON_TOP_DATE DESC, ${SORT_ITEM} ${SORT_ORDER}

mapper.update:
UPDATE WH_COMMENT 
SET 
    COM_BODY = #{COM_BODY}
WHERE
    CON_ID = #{CON_ID}
    AND COM_ID = #{COM_ID}

UPDATE WH_COMMENT 
SET 
    COM_USE_YN = '0'
WHERE
    CON_ID = #{CON_ID}
    AND COM_ID = #{COM_ID}

UPDATE WH_CONTENT
SET
	CON_PRIOT = ${change}
WHERE CON_PRIOT = ${object}

UPDATE WH_CONTENT
SET
	CON_PRIOT = ${change}
WHERE CON_ID = ${conId}

