FROM WH_SUBSCRIBE
WHERE MEM_ID = #{MEM_ID}
  AND PRS_ID = #{TARGET_ID}
  AND EXPD_DATE > NOW() -- 만료일이 안 지났는지 확인
  AND SUB_USE_YN = 1
